class EventBus:
    def __init__(self):
        self._handlers: Dict[str, List[Callable]] = {}

    def subscribe(self, event_type: str, handler: Callable) -> None:
        self._handlers.setdefault(event_type, []).append(handler)

    async def publish(self, event) -> None:
        for handler in self._handlers.get(type(event).__name__, []):
            await handler(event)

# Wiring
event_bus = EventBus()
projection = OrderDetailsProjection(session)
event_bus.subscribe("OrderCreated", projection.handle_order_created)
event_bus.subscribe("OrderPlaced",  projection.handle_order_placed)
